import React, { useRef } from "react";
import "./Testimonials.css";
import TestimonialCard from "./TestimonialCard";

const Testimonials = () => {
  const scrollRef = useRef(null);

  const scroll = (direction) => {
    if (!scrollRef.current) return;
    const scrollAmount = scrollRef.current.offsetWidth * 0.8; // scroll by ~80% of the visible width
    scrollRef.current.scrollBy({
      left: direction === "left" ? -scrollAmount : scrollAmount,
      behavior: "smooth",
    });
  };

  return (
    <div className="testimonials">
      <div className="title-box">
        <h1 className="title">Testimonials</h1>
        <p className="text">Hear what my colleagues have to say</p>
      </div>

      <div className="testimonials-wrapper">
        <button className="scroll-btn left" onClick={() => scroll("left")}>
          &#8249;
        </button>

        <div className="testimonials-frame" ref={scrollRef}>
          <TestimonialCard index={0} />
          <TestimonialCard index={1} />
          <TestimonialCard index={2} />
        </div>

        <button className="scroll-btn right" onClick={() => scroll("right")}>
          &#8250;
        </button>
      </div>
    </div>
  );
};

export default Testimonials;
